// // This is a 5-bit Johnson counter with asynchronous reset and synchronous clock. It performs a shift operation based on the inverted feedback from the first input bit to the last output bit.
module JohnsonCounter(  
    input clk,  
    input reset,  
    output reg [4:0] q  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            q <= 5'b00000;  
        else  
            q <= {q[3:0], ~q[4]};  
    end  
endmodule
